    local distanceMeters, distanceError = distanceBetweenZones(fromZoneName, toZoneName)
    if not distanceMeters then
      return haltAutomation("convoy_virtual_leg_failed", distanceError)
    end

    local speedMetersPerSecond = config.virtualization.effectiveSpeedKph / 3.6
    local durationSeconds = math.max(
      config.virtualization.minimumVirtualLegSeconds,
      distanceMeters / speedMetersPerSecond
    )
    local now = timer.getTime()

    controller.virtualLeg = {
      fromZoneName = fromZoneName,
      toZoneName = toZoneName,
      arrivalKind = arrivalKind,
      sectionIndex = sectionIndex,
      distanceMeters = distanceMeters,
      durationSeconds = durationSeconds,
      startedAt = now,
    }

    updateEntity({
      clearFields = { "runtimeGroupName" },
      representationState = REPRESENTATION_VIRTUAL,
      transitionState = TRANSITION_IDLE,
      movementState = MOVEMENT_VIRTUAL_MOVING,
      segmentProgress = 0,
      lastMovementUpdateCampaignTime = now,
    })

    logInfo("convoy_virtual_leg_started", {
      fromZoneName = fromZoneName,
      toZoneName = toZoneName,
      arrivalKind = arrivalKind,
      distanceMeters = distanceMeters,
      durationSeconds = durationSeconds,
      effectiveSpeedKph = config.virtualization.effectiveSpeedKph,
    })
    return true
  end

  local function tickVirtual()
    local leg = controller.virtualLeg
    if not leg then
      return haltAutomation("convoy_virtual_tick_failed", "virtual entity has no active virtual leg")
    end

    local now = timer.getTime()
    local progress = clamp((now - leg.startedAt) / leg.durationSeconds, 0, 1)
    updateEntity({
      segmentProgress = progress,
      lastMovementUpdateCampaignTime = now,
    })

    if progress < 1 then
      return true
    end

    controller.virtualLeg = nil
    updateEntity({
      routeDistanceMeters = controller.entity.routeDistanceMeters + leg.distanceMeters,
      segmentProgress = 1,
      lastMovementUpdateCampaignTime = now,
    })

    if leg.arrivalKind == "ENTRY" then
      local section = config.zones.revealSections[leg.sectionIndex]
      if not section then
        return haltAutomation("convoy_virtual_arrival_failed", "reveal section is unavailable")
      end
      updateEntity({
        currentSectionIndex = leg.sectionIndex,
        segmentIndex = section.entrySegmentIndex,
        segmentProgress = 0,
      })
      logInfo("convoy_reveal_entry_reached", {
        entryZoneName = section.entry,
        sectionId = section.id,
      })
      return materializeCurrentSection()
    end

    if leg.arrivalKind == "TARGET" then
      updateEntity({
        segmentIndex = finalSegmentIndex(),
        segmentProgress = 1,
        movementState = MOVEMENT_ARRIVED,
      })
      if not controller.arrivalLogged then
        controller.arrivalLogged = true
        logInfo("convoy_route_arrived", {
          targetZoneName = config.zones.target,
        })
      end
      announce("Convoy arrived virtually at " .. config.zones.target)
      return true
    end

    return haltAutomation("convoy_virtual_arrival_failed", "unknown virtual arrival kind")
  end

  materializeCurrentSection = function()
    local section = currentSection()
    if not section then
      return haltAutomation("convoy_materialization_failed", "current reveal section is unavailable")
    end

    local retiredOk, retiredError = ensureRetiredGroupsAreAbsent()
    if not retiredOk then
      return haltAutomation("convoy_materialization_failed", retiredError)
    end

    local entryZone, entryError = zoneByName(section.entry)
    if not entryZone then
      return haltAutomation("convoy_materialization_failed", entryError)
    end

    updateEntity({ transitionState = TRANSITION_MATERIALIZING })
    local nextGeneration = controller.entity.physicalGeneration + 1
    local alias = config.template.runtimeAliasPrefix
      .. "_G" .. string.format("%02d", nextGeneration)

    local constructionOk, spawnerOrError = pcall(function()
      local spawner = SPAWN:NewWithAlias(config.template.groupName, alias)
      return spawner:InitPositionCoordinate(entryZone:GetCoordinate())
    end)
    if not constructionOk or type(spawnerOrError) ~= "table" then
      return haltAutomation(
        "convoy_materialization_failed",
        constructionOk and "SPAWN position initialization returned no spawner" or spawnerOrError
      )
    end

    local spawnOk, groupOrError = pcall(function()
      return spawnerOrError:Spawn()
    end)
    if not spawnOk or type(groupOrError) ~= "table" then
      return haltAutomation(
        "convoy_materialization_failed",
        spawnOk and "SPAWN:Spawn did not return a GROUP wrapper" or groupOrError
      )
    end

    local runtimeGroup = groupOrError
    local pruneOk, livingCountOrError = pruneSpawnedGroupToSlots(
      runtimeGroup,
      controller.entity.survivingVehicleSlots
    )
    if not pruneOk then
      destroyGroupSilently(runtimeGroup)
      return haltAutomation("convoy_materialization_failed", livingCountOrError)
    end

    local routeOk, routeOrError = buildPhysicalWindowRoute(section)
    if not routeOk then
      destroyGroupSilently(runtimeGroup)
      return haltAutomation("convoy_physical_route_failed", routeOrError)
    end

    local assignmentOk, assignmentResult = pcall(function()
      return runtimeGroup:Route(routeOrError.waypoints, 0)
    end)
    if not assignmentOk or not assignmentResult then
      destroyGroupSilently(runtimeGroup)
      return haltAutomation(
        "convoy_physical_route_failed",
        assignmentOk and "route assignment returned nil" or assignmentResult
      )
    end

    local inspectionOk, runtimeNameOrError = pcall(function()
      return runtimeGroup:GetName()
    end)
    if not inspectionOk or type(runtimeNameOrError) ~= "string" then
      destroyGroupSilently(runtimeGroup)
      return haltAutomation("convoy_materialization_failed", runtimeNameOrError)
    end

    controller.spawner = spawnerOrError
    controller.runtimeGroup = runtimeGroup
    controller.routeAssignedGeneration = nextGeneration
    controller.exitSeenSlots = {}
    controller.lastError = nil

    updateEntity({
      physicalGeneration = nextGeneration,
      runtimeGroupName = runtimeNameOrError,
      representationState = REPRESENTATION_PHYSICAL,
      transitionState = TRANSITION_IDLE,
      movementState = MOVEMENT_PHYSICAL_MOVING,
      segmentProgress = 0,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })

    local invariantOk, invariantError = validateRepresentationInvariant()
    if not invariantOk then
      destroyGroupSilently(runtimeGroup)
      controller.runtimeGroup = nil
      controller.spawner = nil
      return haltAutomation("convoy_materialization_failed", invariantError)
    end

    logInfo("convoy_automatically_materialized", {
      sectionId = section.id,
      entryZoneName = section.entry,
      exitZoneName = section.exit,
      runtimeGroupName = runtimeNameOrError,
      livingUnitCount = livingCountOrError,
      physicalWaypointCount = #routeOrError.waypoints,
      physicalRouteZones = table.concat(routeOrError.routeZoneNames, ","),
    })
    announce(
      "Convoy visible in " .. section.id
        .. "\nEntry: " .. section.entry
        .. "\nExit: " .. section.exit
    )
    return true
  end

  local function tickPhysical()
    if not controller.runtimeGroup or not groupIsAlive(controller.runtimeGroup) then
      updateEntity({ movementState = MOVEMENT_DESTROYED })
      controller.halted = true
      logInfo("convoy_destroyed", {})
      announce("Convoy destroyed; automation stopped")
      return false
    end

    local section = currentSection()
    if not section then
      return haltAutomation("convoy_exit_monitor_failed", "current reveal section is unavailable")
    end
    local exitZone, exitError = zoneByName(section.exit)
    if not exitZone then
      return haltAutomation("convoy_exit_monitor_failed", exitError)
    end

    local liveOk, liveUnitsOrError = captureLiveUnits(controller.runtimeGroup)
    if not liveOk then
      return haltAutomation("convoy_exit_monitor_failed", liveUnitsOrError)
    end
    local liveSlots = slotsFromLiveUnits(liveUnitsOrError)
    if #liveSlots < 1 then
      updateEntity({ movementState = MOVEMENT_DESTROYED })
      controller.halted = true
      logInfo("convoy_destroyed", {})
      announce("Convoy destroyed; automation stopped")
      return false
    end

    if not arraysEqual(liveSlots, controller.entity.survivingVehicleSlots) then
      updateEntity({ survivingVehicleSlots = copyArray(liveSlots) })
      logInfo("convoy_losses_observed", {
        survivingVehicleSlots = joinNumbers(liveSlots),
      })
    end

    local newlySeen = {}
    for _, item in ipairs(liveUnitsOrError) do
      if not controller.exitSeenSlots[item.slot] then
        local vec2Ok, vec2OrError = pcall(function()
          return item.unit:GetVec2()
        end)
        if not vec2Ok then
          return haltAutomation("convoy_exit_monitor_failed", vec2OrError)
        end
        if exitZone:IsVec2InZone(vec2OrError) == true then
          controller.exitSeenSlots[item.slot] = true
          newlySeen[#newlySeen + 1] = item.slot
        end
      end
    end

    if #newlySeen > 0 then
      table.sort(newlySeen)
      logInfo("convoy_exit_gate_progress", {
        exitZoneName = section.exit,
        newlySeenSlots = joinNumbers(newlySeen),
        seenSlotCount = countSeenLiveSlots(liveSlots),
        requiredSlotCount = #liveSlots,
      })
    end

    for _, slot in ipairs(liveSlots) do
      if not controller.exitSeenSlots[slot] then
        return true
      end
    end

    return beginDematerialization(section)
  end

  beginDematerialization = function(section)
    if controller.pendingDematerialization then
      return true
    end

    local slotsOk, survivingSlotsOrError = captureSurvivingSlots(controller.runtimeGroup)
    if not slotsOk then
      return haltAutomation("convoy_dematerialization_failed", survivingSlotsOrError)
    end

    local pending = {
      runtimeGroupName = controller.entity.runtimeGroupName,
      sectionId = section.id,
      sectionIndex = controller.entity.currentSectionIndex,
      exitZoneName = section.exit,
      startedAt = timer.getTime(),
      attempts = 0,
    }
    controller.pendingDematerialization = pending

    updateEntity({
      transitionState = TRANSITION_DEMATERIALIZING,
      survivingVehicleSlots = copyArray(survivingSlotsOrError),
      segmentIndex = section.exitSegmentIndex,
      segmentProgress = 1,
      lastMovementUpdateCampaignTime = timer.getTime(),
    })

    local scheduleOk, scheduleResult = pcall(function()
      return timer.scheduleFunction(
        pollPendingDematerialization,
        nil,
        timer.getTime() + config.virtualization.destroyConfirmationPollSeconds
      )
    end)
    if not scheduleOk or scheduleResult == nil then
      return haltAutomation(
        "convoy_dematerialization_failed",
        scheduleOk and "destruction confirmation scheduler returned nil" or scheduleResult
      )
    end

    local destructionOk, destructionError = destroyGroupSilently(controller.runtimeGroup)
    if not destructionOk then
      return haltAutomation("convoy_dematerialization_failed", destructionError)
    end

    logInfo("convoy_automatic_dematerialization_started", {
      sectionId = section.id,
      exitZoneName = section.exit,
      survivingVehicleSlots = joinNumbers(survivingSlotsOrError),
    })
    return true
  end

  finalizeDematerialization = function(pending)
    if controller.pendingDematerialization ~= pending then
      return false
    end

    controller.retiredRuntimeGroupNames[#controller.retiredRuntimeGroupNames + 1] = pending.runtimeGroupName
    controller.pendingDematerialization = nil
    controller.runtimeGroup = nil
    controller.spawner = nil
    controller.routeAssignedGeneration = nil
    controller.exitSeenSlots = {}

    updateEntity({
      clearFields = { "runtimeGroupName" },
      representationState = REPRESENTATION_VIRTUAL,
      transitionState = TRANSITION_IDLE,
      movementState = MOVEMENT_VIRTUAL_MOVING,
      segmentProgress = 0,
    })

    logInfo("convoy_automatically_dematerialized", {
      sectionId = pending.sectionId,
      exitZoneName = pending.exitZoneName,
      retiredRuntimeGroupName = pending.runtimeGroupName,
      destroyConfirmationAttempts = pending.attempts,
    })
    announce("Convoy virtual after " .. pending.sectionId)

    local nextSectionIndex = pending.sectionIndex + 1
    local nextSection = config.zones.revealSections[nextSectionIndex]
    if nextSection then
      return beginVirtualLeg(
        pending.exitZoneName,
        nextSection.entry,
        "ENTRY",
        nextSectionIndex
      )
    end

    return beginVirtualLeg(
      pending.exitZoneName,
      config.zones.target,
      "TARGET",
      nil
    )
  end

  pollPendingDematerialization = function(_, scheduledTime)
    local pending = controller.pendingDematerialization
    if not pending then
      return nil
    end

    pending.attempts = pending.attempts + 1
    local lookupOk, existsOrError = nativeGroupExists(pending.runtimeGroupName)
    if lookupOk and existsOrError == false then
      finalizeDematerialization(pending)
      return nil
    end

    local elapsed = timer.getTime() - pending.startedAt
    if elapsed >= config.virtualization.destroyConfirmationTimeoutSeconds then
      local reason = lookupOk
        and "native runtime group still exists after destruction timeout"
        or "native destruction confirmation failed: " .. tostring(existsOrError)
      haltAutomation("convoy_dematerialization_failed", reason)
      return nil
    end

    return scheduledTime + config.virtualization.destroyConfirmationPollSeconds
  end

  function controller:tick()
    if self.halted then
      return false
    end
    if self.entity.transitionState ~= TRANSITION_IDLE then
      return true
    end
    if self.entity.representationState == REPRESENTATION_VIRTUAL
      and self.entity.movementState == MOVEMENT_VIRTUAL_MOVING then
      return tickVirtual()
    end
    if self.entity.representationState == REPRESENTATION_PHYSICAL
      and self.entity.movementState == MOVEMENT_PHYSICAL_MOVING then
      return tickPhysical()
    end
    return true
  end

  automationTick = function(_, scheduledTime)
    if controller.halted
      or controller.entity.movementState == MOVEMENT_ARRIVED
      or controller.entity.movementState == MOVEMENT_DESTROYED then
      return nil
    end

    local ok, resultOrError = pcall(function()
      return controller:tick()
    end)
    if not ok then
      haltAutomation("convoy_automation_tick_failed", resultOrError)
      return nil
    end
    if resultOrError == false or controller.halted then
      return nil
    end

    return scheduledTime + config.virtualization.automationPollSeconds
  end

  function controller:start()
    local action = "Start convoy"
    if not ensureBootstrapReady(action) then
      return false
    end
    if self.entity.automationStarted == true then
      return reject(action, "automation has already been started")
    end
    if self.entity.movementState ~= MOVEMENT_NOT_STARTED then
      return reject(action, "convoy is not in NOT_STARTED state")
    end

    local firstSection = config.zones.revealSections[config.virtualization.initialSectionIndex]
    if not firstSection then
      return haltAutomation("convoy_automation_start_failed", "initial reveal section is unavailable")
    end

    updateEntity({ automationStarted = true })
    local legOk = beginVirtualLeg(
      config.zones.start,
      firstSection.entry,
      "ENTRY",
      config.virtualization.initialSectionIndex
    )
    if not legOk then
      return false
    end

    local scheduleOk, scheduleResult = pcall(function()
      return timer.scheduleFunction(
        automationTick,
        nil,
        timer.getTime() + 0.1
      )
    end)
    if not scheduleOk or scheduleResult == nil then
      return haltAutomation(
        "convoy_automation_start_failed",
        scheduleOk and "automation scheduler returned nil" or scheduleResult
      )
    end

    self.schedulerId = scheduleResult
    logInfo("convoy_automation_started", {
      schedulerId = scheduleResult,
      startZoneName = config.zones.start,
      firstRevealEntryZoneName = firstSection.entry,
    })
    announce(
      "Convoy automation started"
        .. "\nVirtual from: " .. config.zones.start
        .. "\nFirst reveal: " .. firstSection.entry
    )
    return true
  end

  function controller:showStatus()
    local invariantOk, invariantError = validateRepresentationInvariant()
    local fields = commonFields()
    fields.invariantOk = invariantOk
    fields.lastError = controller.lastError or "none"
    fields.missionTimeSeconds = timer.getTime()
    if not invariantOk then
      fields.invariantError = invariantError
    end
    logger:info("convoy_cache_status", fields)

    local leg = controller.virtualLeg
    announce(
      "Entity: " .. controller.entity.entityId
        .. "\nStarted: " .. tostring(controller.entity.automationStarted == true)
        .. "\nRepresentation: " .. controller.entity.representationState
        .. "\nMovement: " .. controller.entity.movementState
        .. "\nTransition: " .. controller.entity.transitionState
        .. "\nSection: " .. tostring(currentSection() and currentSection().id or "none")
        .. "\nRuntime group: " .. tostring(controller.entity.runtimeGroupName or "none")
        .. "\nVehicle slots: " .. joinNumbers(controller.entity.survivingVehicleSlots)
        .. "\nExit gate: " .. tostring(countSeenLiveSlots(controller.entity.survivingVehicleSlots))
        .. "/" .. tostring(#controller.entity.survivingVehicleSlots)
        .. "\nVirtual leg: " .. tostring(leg and (leg.fromZoneName .. " -> " .. leg.toZoneName) or "none")
        .. "\nInvariant: " .. tostring(invariantOk)
        .. "\nError: " .. tostring(controller.lastError or "none")
    )
  end

  function controller:getState()
    return self.campaignState:getEntitySnapshot(config.scenarioId)
  end

  return controller
end

return ConvoyCacheController
end)()

local TM01B = (function()
local TM01B = {}

local OUTCOME_READY = "READY"
local OUTCOME_FAIL_CONFIGURATION = "FAIL_CONFIGURATION"
local OUTCOME_FAIL_SCRIPT = "FAIL_SCRIPT"

local function join(values)
  if #values == 0 then
    return "none"
  end
  return table.concat(values, ",")
end

local function validateFunction(path, getter, missing)
  local ok, value = pcall(getter)
  if not ok or type(value) ~= "function" then
    missing[#missing + 1] = path
  end
end

local function validateTm01bNativeApis()
  local missing = {}
  validateFunction("timer.scheduleFunction", function()
    return timer and timer.scheduleFunction
  end, missing)
  validateFunction("Group.getByName", function()
    return Group and Group.getByName
  end, missing)
  return #missing == 0, missing
end

local function validateTm01bMooseApis()
  local missing = {}
  validateFunction("GROUP.GetUnits", function()
    return GROUP and GROUP.GetUnits
  end, missing)
  validateFunction("POSITIONABLE.Destroy", function()
    return POSITIONABLE and POSITIONABLE.Destroy
  end, missing)
  validateFunction("POSITIONABLE.GetVec2", function()
    return POSITIONABLE and POSITIONABLE.GetVec2
  end, missing)
  validateFunction("SPAWN.InitPositionCoordinate", function()
    return SPAWN and SPAWN.InitPositionCoordinate
  end, missing)
  validateFunction("SPAWN.Spawn", function()
    return SPAWN and SPAWN.Spawn
  end, missing)
  validateFunction("CONTROLLABLE.Route", function()
    return CONTROLLABLE and CONTROLLABLE.Route
  end, missing)
  validateFunction("ZONE_BASE.GetVec2", function()
    return ZONE_BASE and ZONE_BASE.GetVec2
  end, missing)
  validateFunction("ZONE_BASE.IsVec2InZone", function()
    return ZONE_BASE and ZONE_BASE.IsVec2InZone
  end, missing)
  return #missing == 0, missing
end

local function isInteger(value)
  return type(value) == "number" and value >= 0 and value == math.floor(value)
end

local function validateConfiguration(config)
  local missing = {}
  local errors = {}
  local checked = {}

  local function checkGroup(name)
    if checked["group:" .. tostring(name)] then
      return
    end
    checked["group:" .. tostring(name)] = true
    local ok, groupOrError = pcall(function()
      return GROUP:FindByName(name)
    end)
    if not ok then
      errors[#errors + 1] = tostring(name) .. ": " .. tostring(groupOrError)
    elseif not groupOrError then
      missing[#missing + 1] = name
    end
  end

  local function checkZone(name)
    if checked["zone:" .. tostring(name)] then
      return
    end
    checked["zone:" .. tostring(name)] = true
    local ok, zoneOrError = pcall(function()
      return ZONE:FindByName(name)
    end)
    if not ok then
      errors[#errors + 1] = tostring(name) .. ": " .. tostring(zoneOrError)
    elseif not zoneOrError then
      missing[#missing + 1] = name
    end
  end

  local function requireZoneName(name, description)
    if type(name) ~= "string" or name == "" then
      errors[#errors + 1] = description .. " zone name is missing"
      return false
    end
    checkZone(name)
    return true
  end

  checkGroup(config.template.groupName)
  requireZoneName(config.zones.start, "global route start")
  requireZoneName(config.zones.target, "global route target")

  if type(config.zones.routeAnchors) ~= "table"
    or #config.zones.routeAnchors ~= 7 then
    errors[#errors + 1] = "TM01B requires exactly seven intermediate route anchors"
  else
    for index, zoneName in ipairs(config.zones.routeAnchors) do
      requireZoneName(zoneName, "global route anchor " .. tostring(index))
    end
  end

  local routeAnchorCount = type(config.zones.routeAnchors) == "table"
    and #config.zones.routeAnchors or 0
  local previousExitSegmentIndex = nil

  if type(config.zones.revealSections) ~= "table"
    or #config.zones.revealSections < 1 then
    errors[#errors + 1] = "at least one reveal section is required"
  else
    for sectionIndex, section in ipairs(config.zones.revealSections) do
      if type(section.id) ~= "string" or section.id == "" then
        errors[#errors + 1] = "reveal section id is missing"
      end
      requireZoneName(section.entry, "reveal entry " .. tostring(sectionIndex))
      requireZoneName(section.exit, "reveal exit " .. tostring(sectionIndex))
      if section.entry == section.exit then
        errors[#errors + 1] = "reveal entry and exit names must differ: " .. tostring(section.id)
      end

      if not isInteger(section.entrySegmentIndex)
        or section.entrySegmentIndex > routeAnchorCount then
        errors[#errors + 1] = "invalid reveal entry segment index: " .. tostring(section.id)
      end
      if not isInteger(section.exitSegmentIndex)
        or section.exitSegmentIndex > routeAnchorCount then
        errors[#errors + 1] = "invalid reveal exit segment index: " .. tostring(section.id)
      end
      if isInteger(section.entrySegmentIndex)
        and isInteger(section.exitSegmentIndex)
        and section.exitSegmentIndex < section.entrySegmentIndex then
        errors[#errors + 1] = "reveal exit precedes entry: " .. tostring(section.id)
      end
      if previousExitSegmentIndex ~= nil
        and isInteger(section.entrySegmentIndex)
        and section.entrySegmentIndex < previousExitSegmentIndex then
        errors[#errors + 1] = "reveal sections overlap or are out of order: " .. tostring(section.id)
      end
      if isInteger(section.exitSegmentIndex) then
        previousExitSegmentIndex = section.exitSegmentIndex
      end
    end
  end

  if config.virtualization.initialSectionIndex ~= 1 then
    errors[#errors + 1] = "initialSectionIndex must be 1"
  end
  if type(config.zones.revealSections) == "table"
    and config.virtualization.finalSectionIndex ~= #config.zones.revealSections then
    errors[#errors + 1] = "finalSectionIndex must reference the last reveal section"
  end
  if config.template.expectedVehicleCount ~= 6 then
    errors[#errors + 1] = "TM01B expects exactly six configured vehicle slots"
  end
  if config.virtualization.automaticAdvance ~= true
    or config.virtualization.automaticMaterialization ~= true
    or config.virtualization.automaticDematerialization ~= true then
    errors[#errors + 1] = "TM01B version 4 requires all automatic transitions"
  end
  if config.virtualization.exitPassageMode ~= "EACH_SURVIVING_SLOT_EVER_INSIDE" then
    errors[#errors + 1] = "unsupported exit passage mode"
  end
  if type(config.virtualization.effectiveSpeedKph) ~= "number"
    or config.virtualization.effectiveSpeedKph <= 0 then
    errors[#errors + 1] = "effective virtual speed must be positive"
  end
  if type(config.virtualization.automationPollSeconds) ~= "number"
    or config.virtualization.automationPollSeconds <= 0 then
    errors[#errors + 1] = "automation poll interval must be positive"
  end
  if type(config.virtualization.minimumVirtualLegSeconds) ~= "number"
    or config.virtualization.minimumVirtualLegSeconds <= 0 then
    errors[#errors + 1] = "minimum virtual leg duration must be positive"
  end
  if type(config.virtualization.destroyConfirmationPollSeconds) ~= "number"
    or config.virtualization.destroyConfirmationPollSeconds <= 0 then
    errors[#errors + 1] = "destroy confirmation poll interval must be positive"
  end
  if type(config.virtualization.destroyConfirmationTimeoutSeconds) ~= "number"
    or config.virtualization.destroyConfirmationTimeoutSeconds
      <= config.virtualization.destroyConfirmationPollSeconds then
    errors[#errors + 1] = "destroy confirmation timeout must exceed poll interval"
  end

  local checkedObjectCount = 0
  for _ in pairs(checked) do
    checkedObjectCount = checkedObjectCount + 1
  end

  return {
    valid = #missing == 0 and #errors == 0,
    missing = missing,
    errors = errors,
    checkedObjectCount = checkedObjectCount,
  }
end

function TM01B.start(dependencies)
  local build = dependencies.build
  local config = dependencies.config
  local state = {
    outcome = OUTCOME_FAIL_SCRIPT,
    detail = "bootstrap not completed",
    checkedObjectCount = 0,
  }

  local nativeValid, missingNativeApis = dependencies.runtimeGuard.validateNative()
  if not nativeValid then
    state.detail = "required native DCS APIs are unavailable"
    dependencies.safeReporter.report(
      "native_api_validation_failed",
      OUTCOME_FAIL_SCRIPT,
      "missing=" .. join(missingNativeApis),
      "[OMW][TM01B]"
    )
    return state
  end

  local logger = dependencies.structuredLogger.new("[OMW][TM01B]")

  local function announce(text)
    trigger.action.outText("[OMW][TM01B] " .. text, 15, false)
  end

  local function setOutcome(outcome, detail)
    state.outcome = outcome
    state.detail = detail
    logger:info("bootstrap_outcome", {
      detail = detail,
      outcome = outcome,
    })
  end

  local function runConfigurationValidation()
    local ok, resultOrError = pcall(validateConfiguration, config)
    if not ok then
      setOutcome(OUTCOME_FAIL_SCRIPT, "configuration validation raised an error")
      logger:error("configuration_validation_error", { error = resultOrError })
      return false
    end

    local result = resultOrError
    state.checkedObjectCount = result.checkedObjectCount
    if #result.errors > 0 then
      setOutcome(OUTCOME_FAIL_SCRIPT, "configuration validation failed")
      logger:error("configuration_lookup_error", {
        checkedObjectCount = result.checkedObjectCount,
        errors = join(result.errors),
      })
      return false
    end
    if not result.valid then
      setOutcome(OUTCOME_FAIL_CONFIGURATION, "required Mission Editor objects are missing")
      logger:error("configuration_invalid", {
        checkedObjectCount = result.checkedObjectCount,
        missing = join(result.missing),
      })
      return false
    end

    logger:info("configuration_valid", {
      checkedObjectCount = result.checkedObjectCount,
      configurationVersion = config.configurationVersion,
      globalRouteStart = config.zones.start,
      globalRouteAnchorCount = #config.zones.routeAnchors,
      globalRouteTarget = config.zones.target,
      revealSectionCount = #config.zones.revealSections,
      oneManualStartCommand = true,
      automaticAdvance = true,
      automaticMaterialization = true,
      automaticDematerialization = true,
      exitPassageMode = config.virtualization.exitPassageMode,
      revealEntryZonesDetermineSpawn = true,
      revealExitZonesTerminatePhysicalRoutes = true,
    })
    setOutcome(OUTCOME_READY, "TM01B automatic reveal-window caching is ready")
    return true
  end

  local function protectMenuCallback(commandName, callback)
    return function()
      local ok, callbackError = pcall(callback)
      if not ok then
        logger:error("menu_callback_failed", {
          command = commandName,
          error = callbackError,
          outcome = OUTCOME_FAIL_SCRIPT,
        })
        announce("Menu command failed: " .. commandName)
      end
    end
  end

  logger:info("startup", {
    buildTimestamp = build.buildTimestamp,
    configurationVersion = build.configurationVersion,
    dcsVersion = tostring(_G.DCS_VERSION or _G._DCS_VERSION or "unavailable"),
    expectedMooseBuildCommit = build.expectedMooseBuildCommit,
    expectedMooseBuildTimestamp = build.expectedMooseBuildTimestamp,
    expectedMooseCompression = build.expectedMooseCompression,
    expectedMooseFileSha256 = build.expectedMooseFileSha256,
    expectedMooseIncludeFamily = build.expectedMooseIncludeFamily,
    expectedMooseVersion = build.expectedMooseVersion,
    missionTimeSeconds = timer.getTime(),
    mooseVerificationMode = build.mooseVerificationMode,
    stageId = build.stageId,
    testId = build.testId,
  })

  local tm01bNativeValid, missingTm01bNativeApis = validateTm01bNativeApis()
  if not tm01bNativeValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required TM01B native APIs are unavailable")
    logger:error("tm01b_native_api_validation_failed", {
      missing = join(missingTm01bNativeApis),
    })
    return state
  end

  local baseMooseValid, missingBaseMooseApis = dependencies.runtimeGuard.validateMoose()
  if not baseMooseValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required baseline MOOSE APIs are unavailable")
    logger:error("moose_api_validation_failed", {
      missing = join(missingBaseMooseApis),
    })
    return state
  end

  local tm01bMooseValid, missingTm01bMooseApis = validateTm01bMooseApis()
  if not tm01bMooseValid then
    setOutcome(OUTCOME_FAIL_SCRIPT, "required TM01B MOOSE APIs are unavailable")
    logger:error("tm01b_moose_api_validation_failed", {
      missing = join(missingTm01bMooseApis),
    })
    return state
  end

  logger:info("runtime_api_validation_passed", {
    additionalNativeApiCount = 2,
    additionalMooseApiCount = 8,
  })

  if not runConfigurationValidation() then
    return state
  end

  local campaignStateOk, campaignStateOrError = pcall(function()
    return dependencies.inMemoryCampaignState.new(config)
  end)
  if not campaignStateOk or type(campaignStateOrError) ~= "table" then
    setOutcome(OUTCOME_FAIL_SCRIPT, "CampaignState initialization failed")
    logger:error("campaign_state_initialization_failed", {
      error = campaignStateOk
        and "InMemoryCampaignState.new returned no table"
        or campaignStateOrError,
    })
    return state
  end

  local campaignState = campaignStateOrError
  local controllerOk, controllerOrError = pcall(function()
    return dependencies.convoyCacheController.new({
      announce = announce,
      campaignState = campaignState,
      config = config,
      getBootstrapOutcome = function()
        return state.outcome
      end,
      logger = logger,
    })
  end)
  if not controllerOk or type(controllerOrError) ~= "table" then
    setOutcome(OUTCOME_FAIL_SCRIPT, "cache controller initialization failed")
    logger:error("cache_controller_initialization_failed", {
      error = controllerOk
        and "ConvoyCacheController.new returned no table"
        or controllerOrError,
    })
    return state
  end

  local cacheController = controllerOrError

  local function showStatus()
    logger:info("status_requested", {
      checkedObjectCount = state.checkedObjectCount,
      detail = state.detail,
      outcome = state.outcome,
    })
    announce("Outcome: " .. state.outcome .. "\nDetail: " .. state.detail)
    cacheController:showStatus()
  end

  local function validateFromMenu()
    runConfigurationValidation()
    showStatus()
  end

  local menuOk, menuOrError = pcall(function()
    local rootMenu = MENU_MISSION:New("OMW Tests")
    local testMenu = MENU_MISSION:New(build.stageId, rootMenu)

    MENU_MISSION_COMMAND:New(
      "Start convoy",
      testMenu,
      protectMenuCallback("Start convoy", function()
        cacheController:start()
      end)
    )
    MENU_MISSION_COMMAND:New(
      "Show status",
      testMenu,
      protectMenuCallback("Show status", showStatus)
    )
    MENU_MISSION_COMMAND:New(
      "Validate configuration",
      testMenu,
      protectMenuCallback("Validate configuration", validateFromMenu)
    )

    return {
      root = rootMenu,
      test = testMenu,
    }
  end)

  if not menuOk then
    setOutcome(OUTCOME_FAIL_SCRIPT, "F10 menu creation failed")
    logger:error("menu_creation_failed", { error = menuOrError })
    return state
  end

  state.menu = menuOrError
  state.campaignState = campaignState
  state.cacheController = cacheController
  logger:info("campaign_state_ready", {
    entityId = config.scenarioId,
    initialRoutePosition = config.zones.start,
    persistenceEnabled = false,
  })
  logger:info("menu_ready", {
    path = "OMW Tests / " .. build.stageId,
    primaryCommand = "Start convoy",
  })

  return state
end

return TM01B
end)()

local entryOk, entryResult = pcall(function()
  return TM01B.start({
    build = OMWBuild,
    config = TM01BConfig,
    safeReporter = SafeReporter,
    structuredLogger = StructuredLogger,
    runtimeGuard = RuntimeGuard,
    inMemoryCampaignState = InMemoryCampaignState,
    convoyCacheController = ConvoyCacheController,
  })
end)

local TM01BState = entryResult
if not entryOk then
  SafeReporter.report("bootstrap_uncaught_error", "FAIL_SCRIPT", entryResult, "[OMW][TM01B]")
  TM01BState = {
    outcome = "FAIL_SCRIPT",
    detail = "bootstrap raised an uncaught error",
  }
end
